// frontend/src/components/MovieList.js
import React from 'react';

function MovieList({ movies, onEdit, onDelete }) {
    if (movies.length === 0) {
        return <p>No movies added yet. Add some using the form!</p>;
    }

    return (
        <div className="movie-list">
            {movies.map((movie) => (
                <div key={movie.movieID} className="movie-card">
                    <h3>{movie.title} ({movie.releaseYear})</h3>
                    <p><strong>Director:</strong> {movie.director}</p>
                    <p><strong>Genre:</strong> {movie.genre}</p>
                    <p><strong>Rating:</strong> {movie.rating} / 10</p>
                    <p><strong>ID:</strong> {movie.movieID}</p>
                    <div className="card-buttons">
                        <button onClick={() => onEdit(movie)}>Edit</button>
                        <button onClick={() => onDelete(movie.movieID)} className="delete-btn">Delete</button>
                    </div>
                </div>
            ))}
        </div>
    );
}

export default MovieList;
